7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This entity implements multiple pipeline stages for an axi4 interface.
11	--
12	-- Documentation:
13	-- https://github.com/open-logic/open-logic/blob/main/doc/axi/olo_axi_pl_stage.md
14	--
15	-- Note: The link points to the documentation of the latest release. If you
16	--       use an older version, the documentation might not match the code.
17	
18	---------------------------------------------------------------------------------------------------
19	-- Libraries
20	---------------------------------------------------------------------------------------------------
21	library ieee;
22	    use ieee.std_logic_1164.all;
23	    use ieee.numeric_std.all;
24	
25	---------------------------------------------------------------------------------------------------
26	-- Entity
27	---------------------------------------------------------------------------------------------------
28	entity olo_axi_pl_stage is
29	    generic (
30	        AddrWidth_g : positive := 32;
31	        DataWidth_g : positive := 32;
32	        IdWidth_g   : natural  := 0;
33	        UserWidth_g : natural  := 0;
34	        Stages_g    : positive := 1
35	    );
36	    port (
37	        -- Control Signals
38	        Clk        : in    std_logic;
39	        Rst        : in    std_logic;
40	
41	        -- Slave Interface
42	        -- write address channel
43	        S_AwId     : in    std_logic_vector(IdWidth_g - 1 downto 0)   := (others => '0');
44	        S_AwAddr   : in    std_logic_vector(AddrWidth_g - 1 downto 0);
45	        S_AwValid  : in    std_logic;
46	        S_AwReady  : out   std_logic;
47	        S_AwLen    : in    std_logic_vector(7 downto 0)               := (others => '0');
48	        S_AwSize   : in    std_logic_vector(2 downto 0)               := (others => '0');
49	        S_AwBurst  : in    std_logic_vector(1 downto 0)               := (others => '0');
50	        S_AwLock   : in    std_logic                                  := '0';
51	        S_AwCache  : in    std_logic_vector(3 downto 0)               := (others => '0');
52	        S_AwProt   : in    std_logic_vector(2 downto 0)               := (others => '0');
53	        S_AwQos    : in    std_logic_vector(3 downto 0)               := (others => '0');
54	        S_AwUser   : in    std_logic_vector(UserWidth_g - 1 downto 0) := (others => '0');
55	        S_AwRegion : in    std_logic_vector(3 downto 0)               := (others => '0');
56	        -- write data channel
57	        S_WData    : in    std_logic_vector(DataWidth_g - 1 downto 0);
58	        S_WStrb    : in    std_logic_vector(DataWidth_g / 8 - 1 downto 0);
59	        S_WValid   : in    std_logic;
60	        S_WReady   : out   std_logic;
61	        S_WLast    : in    std_logic                                  := '1';
62	        S_WUser    : in    std_logic_vector(UserWidth_g - 1 downto 0) := (others => '0');
63	        -- write response channel
64	        S_BId      : out   std_logic_vector(IdWidth_g - 1 downto 0);
65	        S_BResp    : out   std_logic_vector(1 downto 0);
66	        S_BValid   : out   std_logic;
67	        S_BReady   : in    std_logic;
68	        S_BUser    : out   std_logic_vector(UserWidth_g - 1 downto 0);
69	        -- read address channel
70	        S_ArId     : in    std_logic_vector(IdWidth_g - 1 downto 0)   := (others => '0');
71	        S_ArAddr   : in    std_logic_vector(AddrWidth_g - 1 downto 0);
72	        S_ArValid  : in    std_logic;
73	        S_ArReady  : out   std_logic;
74	        S_ArLen    : in    std_logic_vector(7 downto 0)               := (others => '0');
75	        S_ArSize   : in    std_logic_vector(2 downto 0)               := (others => '0');
76	        S_ArBurst  : in    std_logic_vector(1 downto 0)               := (others => '0');
77	        S_ArLock   : in    std_logic;
78	        S_ArCache  : in    std_logic_vector(3 downto 0)               := (others => '0');
79	        S_ArProt   : in    std_logic_vector(2 downto 0)               := (others => '0');
80	        S_ArQos    : in    std_logic_vector(3 downto 0)               := (others => '0');
81	        S_ArUser   : in    std_logic_vector(UserWidth_g - 1 downto 0) := (others => '0');
82	        S_ArRegion : in    std_logic_vector(3 downto 0)               := (others => '0');
83	        -- read data channel
84	        S_RId      : out   std_logic_vector(IdWidth_g - 1 downto 0);
85	        S_RData    : out   std_logic_vector(DataWidth_g - 1 downto 0);
86	        S_RValid   : out   std_logic;
87	        S_RReady   : in    std_logic;
88	        S_RResp    : out   std_logic_vector(1 downto 0);
89	        S_RLast    : out   std_logic;
90	        S_RUser    : out   std_logic_vector(UserWidth_g - 1 downto 0);
91	
92	        -- output interface
93	        -- write address channel
94	        M_AwId     : out   std_logic_vector(IdWidth_g - 1 downto 0);
95	        M_AwAddr   : out   std_logic_vector(AddrWidth_g - 1 downto 0);
96	        M_AwValid  : out   std_logic;
97	        M_AwReady  : in    std_logic;
98	        M_AwLen    : out   std_logic_vector(7 downto 0);
99	        M_AwSize   : out   std_logic_vector(2 downto 0);
100	        M_AwBurst  : out   std_logic_vector(1 downto 0);
101	        M_AwLock   : out   std_logic;
102	        M_AwCache  : out   std_logic_vector(3 downto 0);
103	        M_AwProt   : out   std_logic_vector(2 downto 0);
104	        M_AwQos    : out   std_logic_vector(3 downto 0);
105	        M_AwUser   : out   std_logic_vector(UserWidth_g - 1 downto 0);
106	        M_AwRegion : out   std_logic_vector(3 downto 0);
107	        -- write data channel
108	        M_WData    : out   std_logic_vector(DataWidth_g - 1 downto 0);
109	        M_WStrb    : out   std_logic_vector(DataWidth_g / 8 - 1 downto 0);
110	        M_WValid   : out   std_logic;
111	        M_WReady   : in    std_logic;
112	        M_WLast    : out   std_logic;
113	        M_WUser    : out   std_logic_vector(UserWidth_g - 1 downto 0);
114	        -- write response channel
115	        M_BId      : in    std_logic_vector(IdWidth_g - 1 downto 0)   := (others => '0');
116	        M_BResp    : in    std_logic_vector(1 downto 0);
117	        M_BValid   : in    std_logic;
118	        M_BReady   : out   std_logic;
119	        M_BUser    : in    std_logic_vector(UserWidth_g - 1 downto 0) := (others => '0');
120	        -- read address channel
121	        M_ArId     : out   std_logic_vector(IdWidth_g - 1 downto 0);
122	        M_ArAddr   : out   std_logic_vector(AddrWidth_g - 1 downto 0);
123	        M_ArValid  : out   std_logic;
124	        M_ArReady  : in    std_logic;
125	        M_ArLen    : out   std_logic_vector(7 downto 0);
126	        M_ArSize   : out   std_logic_vector(2 downto 0);
127	        M_ArBurst  : out   std_logic_vector(1 downto 0);
128	        M_ArLock   : out   std_logic;
129	        M_ArCache  : out   std_logic_vector(3 downto 0);
130	        M_ArProt   : out   std_logic_vector(2 downto 0);
131	        M_ArQos    : out   std_logic_vector(3 downto 0);
132	        M_ArUser   : out   std_logic_vector(UserWidth_g - 1 downto 0);
133	        M_ArRegion : out   std_logic_vector(3 downto 0);
134	        -- read data channel
135	        M_RId      : in    std_logic_vector(IdWidth_g - 1 downto 0)   := (others => '0');
136	        M_RData    : in    std_logic_vector(DataWidth_g - 1 downto 0);
137	        M_RValid   : in    std_logic;
138	        M_RReady   : out   std_logic;
139	        M_RResp    : in    std_logic_vector(1 downto 0);
140	        M_RLast    : in    std_logic                                  := '1';
141	        M_RUser    : in    std_logic_vector(UserWidth_g - 1 downto 0) := (others => '0')
142	    );
143	end entity;
144	
145	---------------------------------------------------------------------------------------------------
146	-- Architecture
147	---------------------------------------------------------------------------------------------------
148	architecture rtl of olo_axi_pl_stage is
149	
150	begin
151	
152	    -- write address channel
153	    b_aw : block is
154	        subtype  AwProtRng_c   is natural range S_AwProt'length-1                   downto 0;
155	        subtype  AwCacheRng_c  is natural range S_AwCache'length+AwProtRng_c'high   downto AwProtRng_c'high+1;
156	        constant AwLockIdx_C : natural := AwCacheRng_c'high+1;
157	        subtype  AwBurstRng_c  is natural range S_AwBurst'length+AwLockIdx_C          downto AwLockIdx_C+1;
158	        subtype  AwSizeRng_c   is natural range S_AwSize'length+AwBurstRng_c'high   downto AwBurstRng_c'high+1;
159	        subtype  AwLenRng_c    is natural range S_AwLen'length+AwSizeRng_c'high     downto AwSizeRng_c'high+1;
160	        subtype  AwAddrRng_c   is natural range S_AwAddr'length+AwLenRng_c'high     downto AwLenRng_c'high+1;
161	        subtype  AwIdRng_c     is natural range S_AwId'length+AwAddrRng_c'high      downto AwAddrRng_c'high+1;
162	        subtype  AwQosRng_c    is natural range S_AwQos'length+AwIdRng_c'high       downto AwIdRng_c'high+1;
163	        subtype  AwUserRng_c   is natural range S_AwUser'length+AwQosRng_c'high     downto AwQosRng_c'high+1;
164	        subtype  AwRegionRng_c is natural range S_AwRegion'length+AwUserRng_c'high  downto AwUserRng_c'high+1;
165	
166	        signal AwDataIn, AwDataOut : std_logic_vector(AwRegionRng_c'high downto 0);
167	    begin
168	        -- map signals into one vector
169	        AwDataIn(AwProtRng_c)   <= S_AwProt;
170	        AwDataIn(AwCacheRng_c)  <= S_AwCache;
171	        AwDataIn(AwLockIdx_C)   <= S_AwLock;
172	        AwDataIn(AwBurstRng_c)  <= S_AwBurst;
173	        AwDataIn(AwSizeRng_c)   <= S_AwSize;
174	        AwDataIn(AwLenRng_c)    <= S_AwLen;
175	        AwDataIn(AwAddrRng_c)   <= S_AwAddr;
176	        AwDataIn(AwIdRng_c)     <= S_AwId;
177	        AwDataIn(AwQosRng_c)    <= S_AwQos;
178	        AwDataIn(AwUserRng_c)   <= S_AwUser;
179	        AwDataIn(AwRegionRng_c) <= S_AwRegion;
180	
181	        -- Pipeline stage
182	        i_pl : entity work.olo_base_pl_stage
183	            generic map (
184	                Width_g    => AwDataIn'length,
185	                UseReady_g => true,
186	                Stages_g   => Stages_g
187	            )
188	            port map (
189	                Clk        => Clk,
190	                Rst        => Rst,
191	                In_Valid   => S_AwValid,
192	                In_Ready   => S_AwReady,
193	                In_Data    => AwDataIn,
194	                Out_Valid  => M_AwValid,
195	                Out_Ready  => M_AwReady,
196	                Out_Data   => AwDataOut
197	            );
198	
199	        -- unmap signals from vector
200	        M_AwProt   <= AwDataOut(AwProtRng_c);
201	        M_AwCache  <= AwDataOut(AwCacheRng_c);
202	        M_AwLock   <= AwDataOut(AwLockIdx_C);
203	        M_AwBurst  <= AwDataOut(AwBurstRng_c);
204	        M_AwSize   <= AwDataOut(AwSizeRng_c);
205	        M_AwLen    <= AwDataOut(AwLenRng_c);
206	        M_AwAddr   <= AwDataOut(AwAddrRng_c);
207	        M_AwId     <= AwDataOut(AwIdRng_c);
208	        M_AwQos    <= AwDataOut(AwQosRng_c);
209	        M_AwUser   <= AwDataOut(AwUserRng_c);
210	        M_AwRegion <= AwDataOut(AwRegionRng_c);
211	    end block;
212	
213	    -- write data channel
214	    b_w : block is
215	        subtype  WDataRng_c is natural range S_WData'length-1              downto 0;
216	        subtype  WStrbRng_c is natural range S_WStrb'length+WDataRng_c'high  downto WDataRng_c'high+1;
217	        constant WLastIdx_c : natural := WStrbRng_c'high+1;
218	        subtype  WUserRng_c is natural range S_WUser'length+WLastIdx_c       downto WLastIdx_c+1;
219	
220	        signal WDataIn, WDataOut : std_logic_vector(WUserRng_c'high downto 0);
221	    begin
222	
223	        -- map signals into one vector
224	        WDataIn(WDataRng_c) <= S_WData;
225	        WDataIn(WStrbRng_c) <= S_WStrb;
226	        WDataIn(WLastIdx_c) <= S_WLast;
227	        WDataIn(WUserRng_c) <= S_WUser;
228	
229	        -- pipeline stage
230	        i_pl : entity work.olo_base_pl_stage
231	            generic map (
232	                Width_g    => WDataIn'length,
233	                UseReady_g => true,
234	                Stages_g   => Stages_g
235	            )
236	            port map (
237	                Clk        => Clk,
238	                Rst        => Rst,
239	                In_Valid   => S_WValid,
240	                In_Ready   => S_WReady,
241	                In_Data    => WDataIn,
242	                Out_Valid  => M_WValid,
243	                Out_Ready  => M_WReady,
244	                Out_Data   => WDataOut
245	            );
246	
247	        -- unmap signals from vector
248	        M_WLast <= WDataOut(WLastIdx_c);
249	        M_WStrb <= WDataOut(WStrbRng_c);
250	        M_WData <= WDataOut(WDataRng_c);
251	        M_WUser <= WDataOut(WUserRng_c);
252	    end block;
253	
254	    -- write response channel
255	    b_b : block is
256	        subtype BRespRng_c is natural range S_BResp'length-1           downto 0;
257	        subtype BIdRng_c   is natural range S_BId'length+BRespRng_c'high downto BRespRng_c'high+1;
258	        subtype BuserRng_c is natural range S_BUser'length+BIdRng_c'high downto BIdRng_c'high+1;
259	
260	        signal BDataIn, BDataOut : std_logic_vector(BuserRng_c'high downto 0);
261	    begin
262	        -- map signals into one vector
263	        BDataIn(BIdRng_c)   <= M_BId;
264	        BDataIn(BRespRng_c) <= M_BResp;
265	        BDataIn(BuserRng_c) <= M_BUser;
266	
267	        -- pipeline stage
268	        i_bch_pl : entity work.olo_base_pl_stage
269	            generic map (
270	                Width_g    => BDataIn'length,
271	                UseReady_g => true,
272	                Stages_g   => Stages_g
273	            )
274	            port map (
275	                Clk        => Clk,
276	                Rst        => Rst,
277	                In_Valid   => M_BValid,
278	                In_Ready   => M_BReady,
279	                In_Data    => BDataIn,
280	                Out_Valid  => S_BValid,
281	                Out_Ready  => S_BReady,
282	                Out_Data   => BDataOut
283	            );
284	
285	        -- unmap signals from vector
286	        S_BId   <= BDataOut(BIdRng_c);
287	        S_BResp <= BDataOut(BRespRng_c);
288	        S_BUser <= BDataOut(BuserRng_c);
289	    end block;
290	
291	    -- read address channel
292	    b_ar : block is
293	        subtype  ArProtRng_c   is natural range S_ArProt'length-1                 downto 0;
294	        subtype  ArCacheRng_c  is natural range S_ArCache'length+ArProtRng_c'high   downto ArProtRng_c'high+1;
295	        constant ArLockIdx_c : natural := ArCacheRng_c'high+1;
296	        subtype  ArBurstRng_c  is natural range S_ArBurst'length+ArLockIdx_c        downto ArLockIdx_c+1;
297	        subtype  ArSizeRng_c   is natural range S_ArSize'length+ArBurstRng_c'high   downto ArBurstRng_c'high+1;
298	        subtype  ArLenRng_c    is natural range S_ArLen'length+ArSizeRng_c'high     downto ArSizeRng_c'high+1;
299	        subtype  ArAddrRng_c   is natural range S_ArAddr'length+ArLenRng_c'high     downto ArLenRng_c'high+1;
300	        subtype  ArIdRng_c     is natural range S_ArId'length+ArAddrRng_c'high      downto ArAddrRng_c'high+1;
301	        subtype  ArQosRng_c    is natural range S_ArQos'length+ArIdRng_c'high       downto ArIdRng_c'high+1;
302	        subtype  ArUserRng_c   is natural range S_ArUser'length+ArQosRng_c'high     downto ArQosRng_c'high+1;
303	        subtype  ArRegionRng_c is natural range S_ArRegion'length+ArUserRng_c'high  downto ArUserRng_c'high+1;
304	
305	        signal ArDataIn, ArDataOut : std_logic_vector(ArRegionRng_c'high downto 0);
306	    begin
307	
308	        -- map signals into one vector
309	        ArDataIn(ArProtRng_c)   <= S_ArProt;
310	        ArDataIn(ArCacheRng_c)  <= S_ArCache;
311	        ArDataIn(ArLockIdx_c)   <= S_ArLock;
312	        ArDataIn(ArBurstRng_c)  <= S_ArBurst;
313	        ArDataIn(ArSizeRng_c)   <= S_ArSize;
314	        ArDataIn(ArLenRng_c)    <= S_ArLen;
315	        ArDataIn(ArAddrRng_c)   <= S_ArAddr;
316	        ArDataIn(ArIdRng_c)     <= S_ArId;
317	        ArDataIn(ArQosRng_c)    <= S_ArQos;
318	        ArDataIn(ArUserRng_c)   <= S_ArUser;
319	        ArDataIn(ArRegionRng_c) <= S_ArRegion;
320	
321	        -- pipeline stage
322	        i_pl : entity work.olo_base_pl_stage
323	            generic map (
324	                Width_g    => ArDataIn'length,
325	                UseReady_g => true,
326	                Stages_g   => Stages_g
327	            )
328	            port map (
329	                Clk        => Clk,
330	                Rst        => Rst,
331	                In_Valid   => S_ArValid,
332	                In_Ready   => S_ArReady,
333	                In_Data    => ArDataIn,
334	                Out_Valid  => M_ArValid,
335	                Out_Ready  => M_ArReady,
336	                Out_Data   => ArDataOut
337	            );
338	
339	        -- unmap signals from vector
340	        M_ArProt   <= ArDataOut(ArProtRng_c);
341	        M_ArCache  <= ArDataOut(ArCacheRng_c);
342	        M_ArLock   <= ArDataOut(ArLockIdx_c);
343	        M_ArBurst  <= ArDataOut(ArBurstRng_c);
344	        M_ArSize   <= ArDataOut(ArSizeRng_c);
345	        M_ArLen    <= ArDataOut(ArLenRng_c);
346	        M_ArAddr   <= ArDataOut(ArAddrRng_c);
347	        M_ArId     <= ArDataOut(ArIdRng_c);
348	        M_ArQos    <= ArDataOut(ArQosRng_c);
349	        M_ArUser   <= ArDataOut(ArUserRng_c);
350	        M_ArRegion <= ArDataOut(ArRegionRng_c);
351	    end block;
352	
353	    -- read data channel
354	    b_r : block is
355	        subtype  RDataRng_c is natural range S_RData'length-1             downto 0;
356	        constant RLastIdx_c : natural := RDataRng_c'high+1;
357	        subtype  RRespRng_c is natural range S_RResp'length+RLastIdx_c    downto RLastIdx_c+1;
358	        subtype  RIdRng_c   is natural range S_RId'length+RRespRng_c'high downto RRespRng_c'high+1;
359	        subtype  RUserRng_c is natural range S_RUser'length+RIdRng_c'high downto RIdRng_c'high+1;
360	
361	        signal RDataIn, RDataOut : std_logic_vector(RUserRng_c'high downto 0);
362	    begin
363	        -- map signals into one vector
364	        RDataIn(RDataRng_c) <= M_RData;
365	        RDataIn(RRespRng_c) <= M_RResp;
366	        RDataIn(RLastIdx_c) <= M_RLast;
367	        RDataIn(RIdRng_c)   <= M_RId;
368	        RDataIn(RUserRng_c) <= M_RUser;
369	
370	        -- pipeline stage
371	        i_rch_pl : entity work.olo_base_pl_stage
372	            generic map (
373	                Width_g    => RDataIn'length,
374	                UseReady_g => true,
375	                Stages_g   => Stages_g
376	            )
377	            port map (
378	                Clk        => Clk,
379	                Rst        => Rst,
380	                In_Valid   => M_RValid,
381	                In_Ready   => M_RReady,
382	                In_Data    => RDataIn,
383	                Out_Valid  => S_RValid,
384	                Out_Ready  => S_RReady,
385	                Out_Data   => RDataOut
386	            );
387	
388	        -- unmap signals from vector
389	        S_RData <= RDataOut(RDataRng_c);
390	        S_RResp <= RDataOut(RRespRng_c);
391	        S_RLast <= RDataOut(RLastIdx_c);
392	        S_RId   <= RDataOut(RIdRng_c);
393	        S_RUser <= RDataOut(RUserRng_c);
394	    end block;
395	
396	end architecture;
