6	
7	---------------------------------------------------------------------------------------------------
8	-- Description
9	---------------------------------------------------------------------------------------------------
10	-- This entity implements a pipelinestage with handshaking (AXI-S Ready/Valild). The
11	-- pipeline stage ensures all signals are registered in both directions (including
12	-- Ready). This is important to break long logic chains that can occur in the RDY
13	-- paths because Rdy is often forwarded asynchronously.
14	--
15	-- Documentation:
16	-- https://github.com/open-logic/open-logic/blob/main/doc/base/olo_base_pl_stage.md
17	--
18	-- Note: The link points to the documentation of the latest release. If you
19	--       use an older version, the documentation might not match the code.
20	
21	---------------------------------------------------------------------------------------------------
22	-- Libraries
23	---------------------------------------------------------------------------------------------------
24	
25	library ieee;
26	    use ieee.std_logic_1164.all;
27	    use ieee.numeric_std.all;
28	    use ieee.math_real.all;
29	
30	---------------------------------------------------------------------------------------------------
31	-- Entity
32	---------------------------------------------------------------------------------------------------
33	entity olo_base_pl_stage is
34	    generic (
35	        Width_g     : positive;
36	        UseReady_g  : boolean := true;
37	        Stages_g    : natural := 1
38	    );
39	    port (
40	        -- Control Ports
41	        Clk         : in    std_logic;
42	        Rst         : in    std_logic;
43	        -- Input
44	        In_Valid    : in    std_logic := '1';
45	        In_Ready    : out   std_logic;
46	        In_Data     : in    std_logic_vector(Width_g-1 downto 0);
47	        -- Output
48	        Out_Valid   : out   std_logic;
49	        Out_Ready   : in    std_logic := '1';
50	        Out_Data    : out   std_logic_vector(Width_g-1 downto 0)
51	    );
52	end entity;
53	
54	---------------------------------------------------------------------------------------------------
55	-- Architecture
56	---------------------------------------------------------------------------------------------------
57	architecture rtl of olo_base_pl_stage is
58	
59	    -- Single Stage Entity forward-declaration (defined later in this file)
60	    component olo_private_pl_stage_single is
61	        generic (
62	            Width_g     : positive;
63	            UseReady_g  : boolean   := true
64	        );
65	        port (
66	            Clk         : in    std_logic;
67	            Rst         : in    std_logic;
68	            In_Valid    : in    std_logic;
69	            In_Ready    : out   std_logic;
70	            In_Data     : in    std_logic_vector(Width_g-1 downto 0);
71	            Out_Valid   : out   std_logic;
72	            Out_Ready   : in    std_logic := '1';
73	            Out_Data    : out   std_logic_vector(Width_g-1 downto 0)
74	        );
75	    end component;
76	
77	    -- Types
78	    type Data_t is array (natural range <>) of std_logic_vector(Width_g - 1 downto 0);
79	
80	    -- Signals
81	    signal Data  : Data_t(0 to Stages_g);
82	    signal Valid : std_logic_vector(0 to Stages_g);
83	    signal Ready : std_logic_vector(0 to Stages_g);
84	
85	begin
86	
87	    -- *** On or more stages required ***
88	    g_nonzero : if Stages_g > 0 generate
89	        Valid(0) <= In_Valid;
90	        In_Ready <= Ready(0);
91	        Data(0)  <= In_Data;
92	
93	        g_stages : for i in 0 to Stages_g - 1 generate
94	
95	            -- Signle pipeline stage instance
96	            i_stg : component olo_private_pl_stage_single
97	                generic map (
98	                    Width_g    => Width_g,
99	                    UseReady_g => UseReady_g
100	                )
101	                port map (
102	                    Clk       => Clk,
103	                    Rst       => Rst,
104	                    In_Valid  => Valid(i),
105	                    In_Ready  => Ready(i),
106	                    In_Data   => Data(i),
107	                    Out_Valid => Valid(i + 1),
108	                    Out_Ready => Ready(i + 1),
109	                    Out_Data  => Data(i + 1)
110	                );
111	
112	        end generate;
113	
114	        Out_Valid       <= Valid(Stages_g);
115	        Ready(Stages_g) <= Out_Ready;
116	        Out_Data        <= Data(Stages_g);
117	    end generate;
118	
119	    -- *** Zero stages ***
120	    g_zero : if Stages_g = 0 generate
121	        Out_Valid <= In_Valid;
122	        Out_Data  <= In_Data;
123	        In_Ready  <= Out_Ready;
124	    end generate;
125	
126	end architecture;
127	
128	---------------------------------------------------------------------------------------------------
129	-- Libraries
130	---------------------------------------------------------------------------------------------------
131	
132	library ieee;
133	    use ieee.std_logic_1164.all;
134	    use ieee.numeric_std.all;
135	    use ieee.math_real.all;
136	
137	library work;
138	    use work.olo_base_pkg_attribute.all;
139	
140	---------------------------------------------------------------------------------------------------
141	-- Single Stage Entity
142	---------------------------------------------------------------------------------------------------
143	entity olo_private_pl_stage_single is
144	    generic (
145	        Width_g     : positive;
146	        UseReady_g  : boolean := true
147	    );
148	    port (
149	        -- Control Ports
150	        Clk         : in    std_logic;
151	        Rst         : in    std_logic;
152	        -- Input
153	        In_Valid    : in    std_logic;
154	        In_Ready    : out   std_logic;
155	        In_Data     : in    std_logic_vector(Width_g-1 downto 0);
156	        -- Output
157	        Out_Valid   : out   std_logic;
158	        Out_Ready   : in    std_logic := '1';
159	        Out_Data    : out   std_logic_vector(Width_g-1 downto 0)
160	    );
161	end entity;
162	
163	---------------------------------------------------------------------------------------------------
164	-- Architecture
165	---------------------------------------------------------------------------------------------------
166	architecture rtl of olo_private_pl_stage_single is
167	
168	    -- two process method
169	    type TwoProcess_r is record
170	        DataMain    : std_logic_vector(Width_g - 1 downto 0);
171	        DataMainVld : std_logic;
172	        DataShad    : std_logic_vector(Width_g - 1 downto 0);
173	        DataShadVld : std_logic;
174	        In_Ready    : std_logic;
175	    end record;
176	
177	    signal r, r_next : TwoProcess_r;
178	
179	begin
180	
181	    -- *** Pipeline Stage with RDY ***
182	    g_rdy : if UseReady_g generate
183	
184	        p_comb : process (all) is
185	            variable v         : TwoProcess_r;
186	            variable IsStuck_v : boolean;
187	        begin
188	            -- *** Hold variables stable ***
189	            v := r;
190	
191	            -- *** Simplification Variables ***
192	            IsStuck_v := (r.DataMainVld = '1' and Out_Ready = '0' and (In_Valid = '1' or r.DataShadVld = '1'));
193	
194	            -- *** Handle output transactions ***
195	            if r.DataMainVld = '1' and Out_Ready = '1' then
196	                v.DataMainVld := r.DataShadVld;
197	                v.DataMain    := r.DataShad;
198	                v.DataShadVld := '0';
199	            end if;
